import os
import logging
from google.cloud import storage
from google.auth.transport.requests import Request
from google.oauth2 import service_account
from tensorflow.keras.models import load_model

# Configure logging
logging.basicConfig(level=logging.INFO)
logger = logging.getLogger(__name__)

def get_model_path():
    model_path = os.getenv('MODEL_PATH')
    if not model_path:
        logger.error("Environment variable MODEL_PATH is not set.")
        raise ValueError("Environment variable MODEL_PATH is required.")
    return model_path

def download_latest_model(bucket_name, model_path):
    try:
        credentials = service_account.Credentials.from_service_account_file(
            'path/to/service-account-file.json'
        )
        client = storage.Client(credentials=credentials)
        bucket = client.bucket(bucket_name)
        blobs = list(bucket.list_blobs(prefix=model_path))
        
        if not blobs:
            logger.error("No models found in the specified path.")
            raise FileNotFoundError("No models found in the specified path.")
        
        latest_blob = max(blobs, key=lambda b: b.updated)
        local_model_path = f"/tmp/{latest_blob.name.split('/')[-1]}"
        latest_blob.download_to_filename(local_model_path)
        logger.info(f"Downloaded latest model: {latest_blob.name}")
        return local_model_path
    except Exception as e:
        logger.error(f"Error downloading model: {e}")
        raise

def load_latest_model():
    try:
        model_path = get_model_path()
        bucket_name, path_prefix = model_path.split('/', 1)
        local_model_path = download_latest_model(bucket_name, path_prefix)
        model = load_model(local_model_path)
        logger.info("Model loaded successfully.")
        return model
    except Exception as e:
        logger.error(f"Failed to load model: {e}")
        raise

if __name__ == "__main__":
    model = load_latest_model()
